<?php namespace App\Services\WhatsApp; use Illuminate\Support\Facades\Http; use Illuminate\Support\Facades\Log; class FonnteProvider implements WhatsAppProviderInterface { protected $token; public function __construct() { $this->token = env("WA_FONNTE_TOKEN"); } public function sendMessage(string $phone, string $message): bool { try { $response = Http::withHeaders(["Authorization" => $this->token])->post("https://api.fonnte.com/send", ["target" => $phone, "message" => $message]); return $response->successful(); } catch (\Exception $e) { Log::error("Fonnte API Err: " . $e->getMessage()); return false; } } }
